var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>괴도 르블랑</color>? 그게 누군데?","JPN":"<color=#ffd34c>怪盗ルブラン</color>？　誰だ？","ENG":"<color=#ffd34c>LeBlanc the Thief</color>? Who's that?","TWN":"<color=#ffd34c>怪盜布勒朗</color>？他哪位？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"엉? 대장이라고 설치더니 그것도 몰라?","JPN":"え？　隊長とか名乗っておいて、そんなことも知らないのか？","ENG":"What? You said you're the leader, how do you not know?","TWN":"什麼？你不是自稱為隊長嗎？竟然連這個都不知道？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"쯧쯧. 역시 우리 사무소 이름은 <color=#ffd34c>제리의 돌격대</color>가 어울리겠어.","JPN":"やれやれ。やはりうちの事務所の名前は<color=#ffd34c>ジェリーの突撃隊</color>がふさわしいな。","ENG":"Hmpf, I'm telling you, we should have named our team <color=#ffd34c>Jerry and the Raiders</color>.","TWN":"嘖嘖，我們事務所的名字果然應該叫<color=#ffd34c>傑瑞突擊隊</color>才對！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"아냐. 아무리 봐도 <color=#ffd34c>숙명의 미키단</color> 쪽이 훨씬 멋있다니까.","JPN":"いや、どう考えても<color=#ffd34c>宿命のミッキー団</color>のほうがかっけえだろ。","ENG":"No. Like I said, <color=#ffd34c>Mickey's Gang of Twilight</color> would have been better.","TWN":"才不是咧，應該叫<color=#ffd34c>宿命的米奇團</color>才對啦！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잡담하지 마. <color=#ffd34c>메이슨 용병 사무소의 떨거지들</color>.","JPN":"うるさいぞ。<color=#ffd34c>メイソン傭兵事務所の3バカトリオ</color>。","ENG":"Stop chattering, <color=#ffd34c>Mason Mercenary Office's Losers</color>.","TWN":"別吵！<color=#ffd34c>梅森傭兵事務所一夥</color>。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그렇게 한눈 팔고 있다간 <color=#ffd34c>괴도 르블랑</color>한테 손쉽게 놀아날 거라고.","JPN":"そうやって油断してたら<color=#ffd34c>怪盗ルブラン</color>のオモチャにされるぞ。","ENG":"We must keep our eyes peeled, or <color=#ffd34c>LeBlanc the Thief</color> will make fools out of us.","TWN":"當心<color=#ffd34c>怪盜布勒朗</color>會趁我們不注意時出手！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"맞아. 위험한 녀석이니 조심해야할 필요가 있지.","JPN":"そうだな。危ないやつだから気をつけねば。","ENG":"You're right. He's dangerous. We must be careful.","TWN":"沒錯，那傢伙很危險，必須小心！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"음, 음. 그럼, 그럼. 아주 위험한 녀석이니까.","JPN":"うむ、そうとも。とても危険だもんな。","ENG":"Uh-huh. That's right. He's very dangerous.","TWN":"嗯嗯嗯，沒錯沒錯，那傢伙非常危險！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그러니까 누가 설명 좀 해달라고!","JPN":"だから誰か説明してくれよ！","ENG":"So, somebody explains it to me!","TWN":"所以誰來解釋一下！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"누구야? 대체 그 괴도 어쩌고가?","JPN":"誰なんだ？　その怪盗なんちゃらは？","ENG":"Who the hell is this thief?","TWN":"他到底是誰？那個怪盜是什麼來頭？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"크, 크흠…….","JPN":"こ、こほん……","ENG":"K-kahem...","TWN":"嗯，這個嘛……"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"그게 워낙 설명하기 복잡해서…….","JPN":"それが、とても説明がしにくいんだが……","ENG":"It's complicated...","TWN":"說來話長……"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"……?","JPN":"……？","ENG":"……?","TWN":"……？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하아……. 머릿수 채우려고 이 녀석들까지 데려온 게 잘못이지.","JPN":"はあ……頭数をそろえようとこいつらまで連れてきた俺がバカだった……","ENG":"*Sigh...* I can't believe I brought these fools as backup.","TWN":"哀……都怪我不好，不該為了湊人數硬把他們帶來。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>괴도 르블랑</color>은 용병 업계에서 치를 떠는 유명한 도둑이야.","JPN":"<color=#ffd34c>怪盗ルブラン</color>は傭兵業界で名の知れた泥棒だ。","ENG":"<color=#ffd34c>LeBlanc</color> is a thief notorious in the mercenary industry.","TWN":"<color=#ffd34c>怪盜布勒朗</color>是傭兵界聞之色變的小偷。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"예고장에 적힌 물건은 반드시 훔쳐가거든.","JPN":"予告状に書かれた品物を必ず盗んでいく。","ENG":"When he announces he's going to steal a specific item, he never fails to do so.","TWN":"只要是寫在預告信上的東西，他絕對會偷到手。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금까지 그 어떤 용병들도 훔쳐가는 걸 막기는커녕 그 녀석 그림자도 못 봤다더군.","JPN":"今までどんな傭兵でも犯行を防ぐどころか、奴の影すら見れていないらしい。","ENG":"So far, no mercenary has managed to stop him, or even see his shadow.","TWN":"至今沒有一個傭兵成功阻止他行竊，甚至連個人影都沒能看到。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우리 사무소에서 일하려면 이 정도는 상식으로 알고 있으라고.","JPN":"うちの事務所で働くなら、これぐらいは常識として知っておけ。","ENG":"Things like this are a given if you want to work for me.","TWN":"想在我們事務所工作，這點常識起碼要知道吧！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그림자도 못 봤다는 건 몸놀림이 잽싸다는 건가? 생쥐처럼?","JPN":"影すら見られてないって、すばしっこいってことか？　ネズミみたいに？","ENG":"No one has seen his shadow? Does that mean he's fast? Like a rat?","TWN":"連個人影都看不到，意思是他動作很敏捷嗎？像老鼠一樣？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"철통 같이 퇴로를 차단하는 이 토미 더 다이하드 님과 좋은 승부가 되겠군.","JPN":"鉄壁のごとく退路を断つこのトミー・ザ・ダイハード様といい勝負になりそうだな。","ENG":"He's going to be a good challenge for me, Tommy the Die-hard, who can block enemies like no other.","TWN":"看我這個銅牆鐵壁怎麼圍捕他，來和頑強·湯米一較高下吧！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그 생쥐 녀석, 오늘은 날을 잘못 잡은 거야.","JPN":"そのネズミ野郎、今日はついてない日になるぞ。","ENG":"That rat picked the wrong man to mess with.","TWN":"今天就是那鼠輩的死期！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"야, 너 저번에 사무실에서…….","JPN":"でもさ、お前この前事務所で……","ENG":"Hey, the last time at the office, you—","TWN":"喂，上次在事務所……"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"쉿. 부엌에서 생쥐 보고 비명 지른 거 얘기하면 토라질 거야.","JPN":"シッ。キッチンでネズミをみて叫んだのをバラしたら拗ねちゃうから、黙っててやれよ。","ENG":"Shh. Don't say anything about him screaming at a mouse in the kitchen. He will get salty.","TWN":"噓！不能把他上次在廚房看到老鼠大叫的事說出來啦，他會生氣！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……보기 좋은 우정이군 그래.","JPN":"……涙が出そうなほどの美しい友情だな。","ENG":"... You're such good friends, aren't you?","TWN":"……你們的友情還真感人。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아무튼 그런 녀석을 상대하려면 우리도 만반의 준비를 해야 한다고.","JPN":"とにかく、そんな奴を相手にするんだから俺たちも万端の準備をする必要があるんだよ。","ENG":"Anyway, to catch someone like that, we must be fully prepared.","TWN":"總之，要想對付那傢伙，我們就必須做好萬全的準備！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어설프게 굴다간 그 녀석 그림자도 못 볼 거야.","JPN":"なめてると、奴にしてやられるぞ。","ENG":"Or we might not even see his shadow.","TWN":"再這樣嘻嘻哈哈的，到時候連那傢伙的人影都看不到。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"우리가 지켜야 하는 건 물건이 아니잖아?","JPN":"俺たちが守る対象は物じゃないだろ？","ENG":"What we have to protect is not exactly an item.","TWN":"我們要保護的不是某個東西吧？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그렇지.","JPN":"まあな。","ENG":"No.","TWN":"對。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"예고장에 적힌 물건은 반드시 훔쳐가는 도둑이라며?","JPN":"予告状に書いた品物は必ず盗む泥棒だろ？","ENG":"Didn't you say he's a thief who steals an \\"item\\" he wants?","TWN":"你不是說只要是寫在預告信上的東西，他絕對會偷到手嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그러니까.","JPN":"そうだ。","ENG":"Exactly.","TWN":"我的意思是…"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"그러니까…… 우린 뭘 지키면 되는 거라고?","JPN":"だったら……俺らは何を守ればいいんだ？","ENG":"So... what are we supposed to protect?","TWN":"我的意思是……我們到底要保護什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……이런 녀석들을 데리고 괴도를 잡아야 한다니.","JPN":"……こんなやつらをつれて怪盗を捕まえなければならないなんて。","ENG":"I can't believe I'm relying on you guys to catch this thief.","TWN":"……我竟然帶這些二百五來抓怪盜。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우리가 지켜야 할 건 여기 이 방 안에 있는…….","JPN":"俺たちが守るべきものはこの部屋にいる……","ENG":"What we have to protect is in this room, and it's...","TWN":"我們要保護的，就是這個房裡的……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"강아지다.","JPN":"仔犬だ。","ENG":"A puppy.","TWN":"狗狗！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L8_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"강아지 처지가 우리보다 낫네. 이 방문 크기 좀 봐.","JPN":"仔犬のくせにいい暮らししてんな。ほら、この扉の大きさを見ろよ。","ENG":"This puppy is better off than we are. Look at the size of this door.","TWN":"狗狗過得比我們還爽欸！看看這房間門有多大！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"요샌 반려 동물에게도 유산을 물려준다며? 차라리 동물이 되고 싶어지는걸.","JPN":"最近はペットに財産を相続する人もいるらしいな。動物に生まれ変わりたいくらいだ。","ENG":"Some people nowadays leave their inheritance to their pets, huh? I wish I were an animal.","TWN":"我聽說最近還有人會留遺產給動物欸？當條狗都比當人好！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다들 정신 똑바로 차려. 인간이길 포기하지는 말자고.","JPN":"おい、しっかりしろ。人間であることを諦めるな。","ENG":"Stay frosty, guys. Let's not give up on our humanity just yet.","TWN":"你們給我有骨氣一點！好好人不當，當什麼狗！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"쳇. 리플레이서 사태 때 받은 보상금만 있었어도 이런 말도 안 되는 경호 의뢰는 안 했을 텐데.","JPN":"ちっ、リプレイサー事件でもらった金さえありゃ、こんなバカげた警護依頼なんかやらなくてよかったのにな。","ENG":"Bah. We wouldn't have accepted this ridiculous job if we still had the money from the Replacer incident.","TWN":"嘖！要是有克隆集團事件的獎金，我們哪需要接這種委託！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"일이 왜 이렇게 됐는지만 제대로 기억하면 돼.","JPN":"なぜこういうことになったのかだけ、ちゃんと覚えてりゃいい。","ENG":"Just remember why we don't have it anymore.","TWN":"你只需要記得，是誰把我們害得這麼慘的就好！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"알아, 알아. 네가 백 번은 더 말했잖아. 이게 다 그 여자 때문이라고.","JPN":"はいはい。かれこれ100回以上聞いているからな。全部あの女のせいだろ。","ENG":"I know. You told us at least a hundred times. It's because of that dratted woman.","TWN":"知道啦！你已經說過幾百次，都是那個女人害的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"바로 그거야. 그 원한을 잊지 말자고.","JPN":"そう、それだ。その恨みを忘れないようにしよう。","ENG":"That's right. Don't forget we've got a score to settle with her.","TWN":"沒錯！此仇不可忘！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"자. 너희들은 의뢰주에게 가서 경호 배치 지도 보고하면서 계약서에 서명 받아와.","JPN":"さあ、あんたたちは依頼主の所に行って、警護配置図の報告と契約書にサインをもらってきてくれ。","ENG":"Now, I want you to show the client our guard positions and get his signature on this contract.","TWN":"好了，你們去找委託人，跟他報告守衛的配置圖，然後請他在合約上簽名。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"가는 길에 다른 경호 인력이랑 시비 붙지 않게 조심하고.","JPN":"途中で他の警護要員とトラブルにならないように気を付けろ。","ENG":"Be careful not to pick a fight with other bodyguard teams on your way.","TWN":"去的時候小心不要和其他守衛發生爭執。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다들 괴도 르블랑을 잡아서 포상금 받겠다는 생각에 예민해져 있을 테니까.","JPN":"みんな怪盗ルブランを捕まえて褒賞金を手に入れようと、ピリピリしているはずだからな。","ENG":"Everyone's on edge, wanting to catch LeBlanc so badly for the reward money.","TWN":"畢竟現在大家應該都正繃緊神經，想抓到怪盜布勒朗領取巨額獎金。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"응? 그럼 넌 어떻게 할 건데?","JPN":"え？　お前は何をするんだ？","ENG":"Okay, then what are you going to do?","TWN":"嗯？那你要做什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그야 르블랑이 들어올 만한 곳에 덫을 좀 설치해 둬야지.","JPN":"俺はルブランの侵入経路になりそうな場所に罠を仕掛けておく。","ENG":"I'm going to set up some traps where LeBlanc might appear.","TWN":"我當然是去布勒朗可能會出現的地方設陷阱！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"생쥐를 잡는 데는 쥐덫이 제일이니까.","JPN":"泥棒ネズミを捕まえるには、ネズミ捕りが一番だろ。","ENG":"You can't catch a rat without traps, now can you?","TWN":"捕鼠當然要設陷阱囉！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……좋아. 설치는 다 했고.","JPN":"……よし、仕掛けはこれでOKだな。","ENG":"Alright, I set them all up.","TWN":"……OK，都設好了！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_13"},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런데 토미 녀석들은 왜 아직도 안 와? 설마 길이라도 잃어버린 건가?","JPN":"しかし、トミーの奴らはまだか？　迷子にでもなっちまったか？","ENG":"Now, where are Tommy and the others? Are they lost?","TWN":"湯米他們怎麼動作這麼慢？該不會是迷路了？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니, 아무리 바보들이라도 그렇지 다 큰 어른들인데 설마.","JPN":"いや、いくらバカでも大の大人だし、さすがにないか。","ENG":"Nah, they can't be that stupid. They're old enough to find their way back.","TWN":"不會的，就算他們再怎麼笨，好歹也是大人了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나 참. 집이 쓸데없이 넓으니까 이런 걱정도 다 해보는군.","JPN":"ったく。家が無駄に広いせいか、余計なことまで心配してしまうな。","ENG":"Geez, why am I even worried? I guess this house is too big.","TWN":"真是的，還不是因為這個房子太大，害我還要操這種心！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"?!","JPN":"！？","ENG":"?!","TWN":"？！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"생체 반응?","JPN":"生体反応だと？","ENG":"Vital signs?","TWN":"生命反應？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런. 벌써 나타난 건가, 괴도 르블랑.","JPN":"まいったな。もう現れたのか、怪盗ルブラン。","ENG":"Oh no, is LeBlanc already here?","TWN":"什麼！這麼快就現身了嗎，怪盜布勒朗？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"으응?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐야. 그림자도 못 볼 만큼 잽싸다더니, 센서란 센서는 다 걸리면서 오잖아?","JPN":"なんだ、影も見えないほど素早いと聞いていたが、全センサーに引っかかってるんじゃないか？","ENG":"What's this? If he's so fast, how come he can't avoid any of my sensors?","TWN":"什麼嘛，說什麼連個人影都看不到，結果還不是被感應器感應到？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"밖이 잠잠한 걸 봐선 정원에 깔린 경호 인원은 쉽게 뚫고 들어왔다는 얘긴데…….","JPN":"外は静かということは、庭の警護を簡単に突破してきたということだが……","ENG":"It's quiet outside, which means he breezed his way through the guards in the garden.","TWN":"不過外面一點動靜都沒有，就表示他可以輕易地避開在花園那些守衛……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"왜 내 센서엔 다 걸리는 거지?","JPN":"なぜ俺のセンサーには全て引っかかっているんだ？","ENG":"Then, why is he detected by my sensors?","TWN":"怎麼偏偏就被我的感應器抓到？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"훗. 설마……. 잡을 테면 잡아 보란 건가?","JPN":"ふっ、まさか……捕まえられるものなら捕まえてみろ、ってことか？","ENG":"Hah. Is he... challenging me?","TWN":"呵，難道……他是在跟我下戰帖？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아. 어떤 녀석인지는 몰라도 승부욕이 강한 타입이군.","JPN":"いいだろう。どんな奴かわからないが、かなりの負けず嫌いのようだな。","ENG":"Alright, whoever he is, he's got to be the competitive type.","TWN":"很好，雖然不知道他是誰，但看來個性滿好強的！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어디, 그 잘난 괴도의 얼굴이나 한 번 봐 보실까?","JPN":"さて、怪盗様のご尊顔を見てやろうじゃないか。","ENG":"Let's see what this notorious thief looks like.","TWN":"我就來一睹怪盜的廬山真面目吧！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"흔한 좀도둑처럼 복면이라도 뒤집어 쓰고 왔다면 실망이 꽤 크겠……","JPN":"そこら辺のこそ泥みたいな覆面でもかぶっていたらガッカリだな……","ENG":"I would be very disappointed if he came wearing a mask, like a petty burglar—","TWN":"希望他不是像電視上演的那樣，戴著面具出現，那我會很失望……"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"?!","JPN":"！？","ENG":"?!","TWN":"？！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저, 저 녀석은……?","JPN":"あ、あいつは……？","ENG":"Th-that's...","TWN":"那…那傢伙是……？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};